import base64,hashlib,httpx,json
from fastcore.utils import *

# %% ../nbs/00_core.ipynb #527e76df
doms = ("api.openai.com", "api.anthropic.com", "generativelanguage.googleapis.com", "api.deepseek.com",
    'api.fireworks.ai', 'openrouter.ai', 'api.groq.com', 'api.together.xyz', 'api.mistral.ai', 'api.x.ai')

# %% ../nbs/00_core.ipynb #09571365
def _should_cache(url, doms): return any(dom in str(url) for dom in doms)

# %% ../nbs/00_core.ipynb #6924d508
def _cache(key, cfp):
    with open(cfp, "r") as f:
        line = first(f, lambda l: json.loads(l)["key"] == key)
        return json.loads(line) if line else None

# %% ../nbs/00_core.ipynb #72a0213b
def _write_cache(key, content, cfp, hdrs, status_code=200, binary=False):
    with open(cfp, "a") as f: f.write(json.dumps({"key":key, "response": content, "headers":hdrs, "status_code":status_code, "binary":binary})+"\n")

# %% ../nbs/00_core.ipynb #3c7fca19
def _content(r):
    "Extract content from request."
    if not hasattr(r, '_content'): r.read()
    boundary = httpx._multipart.get_multipart_boundary_from_content_type(r.headers.get("Content-Type", "").encode())
    return r.content.replace(boundary, b"cachy-boundary") if boundary else r.content

# %% ../nbs/00_core.ipynb #a69ba22c
def _norm_content(r):
    "Normalize JSON bodies by sorting keys so semantically-equal payloads hash the same."
    c = _content(r)
    if 'json' in r.headers.get('content-type', '').lower():
        try: return json.dumps(json.loads(c), sort_keys=True).encode()
        except Exception: pass
    return c

def _key(r, is_stream=False):
    "Create a unique, deterministic id from the request `r`."
    return hashlib.sha256(f"{r.url.copy_remove_param('key')}{is_stream}".encode() + _norm_content(r)).hexdigest()[:8]

# %% ../nbs/00_core.ipynb #25ced1ba
def _res_hdrs(res, hdrs=None): return {k: v for k, v in res.headers.items() if k.lower() in hdrs} if hdrs else None

# %% ../nbs/00_core.ipynb #60b4da2a
def _is_text(res):
    "Check if response content type is text-like."
    ct = res.headers.get("content-type", "")
    return any(t in ct for t in ("text/", "json", "xml", "javascript", "html"))

# %% ../nbs/00_core.ipynb #37ad35fa
def _apply_async_patch(cfp, doms, hdrs, debug=False):    
    @patch
    async def send(self:httpx._client.AsyncClient, request, **kwargs):
        r = request
        is_stream = kwargs.get("stream")
        if not _should_cache(r.url, doms): return await self._orig_send(r, **kwargs)
        key = _key(r, is_stream=False)
        if res := _cache(key,cfp):
            if debug: print(f"🟢 HIT {key}\n{r.content}")
            content = res['response']
            if res.get('binary'): content = base64.b64decode(content)
            return httpx.Response(status_code=res.get('status_code', 200), content=content, headers=res.get('headers'), request=r)
        res = await self._orig_send(r, **kwargs)
        raw = res.read() if not is_stream else b''.join([c async for c in res.aiter_bytes()])
        binary = not _is_text(res)
        content = base64.b64encode(raw).decode() if binary else raw.decode()
        if debug: print(f"🔴 MISS {key}\n{r.content}")
        headers = _res_hdrs(res, hdrs)
        _write_cache(key, content, cfp, headers, res.status_code, binary=binary)
        return httpx.Response(status_code=res.status_code, content=raw, headers=headers, request=r)

# %% ../nbs/00_core.ipynb #950030b0
def _apply_sync_patch(cfp, doms, hdrs, debug=False):    
    @patch
    def send(self:httpx._client.Client, request, **kwargs):
        r = request
        is_stream = kwargs.get("stream")
        if not _should_cache(r.url, doms): return self._orig_send(r, **kwargs)
        key = _key(r, is_stream=False)
        if res := _cache(key,cfp):
            if debug: print(f"🟢 HIT {key}\n{r.content}")
            content = res['response']
            if res.get('binary'): content = base64.b64decode(content)
            return httpx.Response(status_code=res.get('status_code', 200), content=content, headers=res.get('headers'), request=r)
        res = self._orig_send(r, **kwargs)
        raw = res.read() if not is_stream else b''.join(list(res.iter_bytes()))
        binary = not _is_text(res)
        content = base64.b64encode(raw).decode() if binary else raw.decode()
        if debug: print(f"🔴 MISS {key}\n{r.content}")
        headers = _res_hdrs(res, hdrs)
        _write_cache(key, content, cfp, headers, res.status_code, binary=binary)
        return httpx.Response(status_code=res.status_code, content=raw, headers=headers, request=r)

# %% ../nbs/00_core.ipynb #3be9fe57
def disable_cachy():
    if not hasattr(httpx._client.AsyncClient, '_orig_send'): return
    httpx._client.AsyncClient.send = httpx._client.AsyncClient._orig_send
    httpx._client.Client.send      = httpx._client.Client._orig_send

# %% ../nbs/00_core.ipynb #a8d53f6a
def enable_cachy(cache_dir=None, doms=doms, hdrs=None, debug=False):
    disable_cachy()
    if hdrs is None: hdrs=[]
    cfp = Path(cache_dir or find_file_parents("pyproject.toml") or ".") / "cachy.jsonl"
    cfp.touch(exist_ok=True)   
    _apply_sync_patch(cfp, doms, hdrs, debug)
    _apply_async_patch(cfp, doms, hdrs, debug)
